#!/usr/bin/env node
/**
 * Bundles all accelerator reference corpora into generated modules.
 * Re-run after editing /katalon sources or /reference markdown.
 */
import { readFileSync, writeFileSync, readdirSync } from 'fs'
import { dirname, join } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const root = join(__dirname, '..')

// ---- Katalon ----------------------------------------------------------------
const kwDir = join(root, 'katalon/Keywords/com/nttdata/guidewire')
const KATALON_FILES = {
  GuidewireUI: 'GuidewireUI.groovy',
  LoginActions: 'LoginActions.groovy',
  TestData: 'TestData.groovy',
  PolicyCenterActions: 'PolicyCenterActions.groovy',
  ClaimCenterActions: 'ClaimCenterActions.groovy',
  BillingCenterActions: 'BillingCenterActions.groovy',
  JutroActions: 'JutroActions.groovy'
}

const katalonLibraries = {}
for (const [key, file] of Object.entries(KATALON_FILES)) {
  katalonLibraries[key] = readFileSync(join(kwDir, file), 'utf8')
}

writeFileSync(
  join(root, 'src/lib/katalonReference.generated.js'),
  `// AUTO-GENERATED by scripts/bundle-reference-material.js — do not edit by hand.
// Re-run: npm run bundle:reference

export const KATALON_SHARED_LIBS = ${JSON.stringify(['GuidewireUI', 'LoginActions', 'TestData'], null, 2)}

export const KATALON_PRODUCT_LIBS = ${JSON.stringify(
    {
      PolicyCenter: 'PolicyCenterActions',
      ClaimCenter: 'ClaimCenterActions',
      BillingCenter: 'BillingCenterActions',
      Jutro: 'JutroActions',
      'Cross-suite': ['PolicyCenterActions', 'ClaimCenterActions', 'BillingCenterActions', 'JutroActions']
    },
    null,
    2
  )}

export const KATALON_LIBRARIES = ${JSON.stringify(katalonLibraries, null, 2)}
`
)
console.log('Wrote src/lib/katalonReference.generated.js')

// ---- GW Cloud standards -----------------------------------------------------
const standardsDir = join(root, 'reference/gw-cloud-standards')
const standardsFiles = readdirSync(standardsDir).filter((f) => f.endsWith('.md'))
const standardsDocs = {}
for (const file of standardsFiles) {
  const key = file.replace(/\.md$/, '')
  standardsDocs[key] = readFileSync(join(standardsDir, file), 'utf8')
}

const CODE_REVIEW_PROFILE_MAP = {
  standards: ['cross-cutting', 'standards'],
  performance: ['cross-cutting', 'performance'],
  upgrade: ['cross-cutting', 'upgrade'],
  security: ['cross-cutting', 'security']
}

// ---- Ski releases -----------------------------------------------------------
const skiDir = join(root, 'reference/ski-releases')
const skiFiles = readdirSync(skiDir).filter((f) => f.endsWith('.md'))
const skiReleaseDocs = {}
for (const file of skiFiles) {
  const key = file.replace(/\.md$/, '')
  skiReleaseDocs[key] = readFileSync(join(skiDir, file), 'utf8')
}

const SKI_RELEASE_SLUGS = {
  Innsbruck: 'innsbruck',
  Hakuba: 'hakuba',
  Garmisch: 'garmisch',
  'Las Leñas': 'las-lenas',
  Palisades: 'palisades',
  'Next (unannounced)': 'next'
}

writeFileSync(
  join(root, 'src/lib/gwReference.generated.js'),
  `// AUTO-GENERATED by scripts/bundle-reference-material.js — do not edit by hand.
// Re-run: npm run bundle:reference

export const CODE_REVIEW_PROFILE_MAP = ${JSON.stringify(CODE_REVIEW_PROFILE_MAP, null, 2)}

export const GW_STANDARDS_DOCS = ${JSON.stringify(standardsDocs, null, 2)}

export const SKI_RELEASE_SLUGS = ${JSON.stringify(SKI_RELEASE_SLUGS, null, 2)}

export const SKI_RELEASE_DOCS = ${JSON.stringify(skiReleaseDocs, null, 2)}
`
)
console.log('Wrote src/lib/gwReference.generated.js')
